import{_ as r,c as t,o as s,ah as a}from"./chunks/framework.RCw5T9E9.js";const c=JSON.parse('{"title":"Чёрный список","description":"","frontmatter":{"title":"Чёрный список"},"headers":[],"relativePath":"ru/props/blacklist.md","filePath":"ru/props/blacklist.md"}'),n={name:"ru/props/blacklist.md"};function l(e,o,i,p,g,h){return s(),t("div",null,[...o[0]||(o[0]=[a('<h1 id="черныи-список-компонентов-props" tabindex="-1">Чёрный список компонентов (Props) <a class="header-anchor" href="#черныи-список-компонентов-props" aria-label="Permalink to &quot;Чёрный список компонентов (Props)&quot;">​</a></h1><p><strong>Чёрный список</strong> во вкладке <strong>Props</strong> — это набор <strong>имён Vue-компонентов</strong>, которые исключаются из дерева инспектора и не отображаются в таблице. Фильтрация применяется <strong>до построения списка props</strong>, поэтому скрытые компоненты не участвуют в обычном обходе дерева.</p><p>Общее описание вкладки Props: <a href="/qa-tools/docs/ru/props/general.html">Основные возможности</a>.</p><p>Не путайте этот список с <strong>чёрным списком сайтов</strong> для <strong>автозапуска</strong> оверлея (настройки <strong>General / Auto Run</strong>): здесь фильтрация относится только к <strong>именам компонентов</strong>.</p><hr><h2 id="где-добавить-и-убрать" tabindex="-1">Где добавить и убрать <a class="header-anchor" href="#где-добавить-и-убрать" aria-label="Permalink to &quot;Где добавить и убрать&quot;">​</a></h2><p>Добавить компонент в чёрный список можно двумя способами.</p><ul><li><strong>Через контекстное меню строки в таблице Props</strong> — команда добавляет имя текущего компонента в активный список блокировки.</li><li><strong>В Options</strong> — секция <strong>Component Blacklist</strong> в блоке <strong>Props</strong> позволяет просматривать правила, добавлять новые строки, переключать состояние записи и удалять ненужные элементы.</li></ul><p>Если имя уже присутствует в списке, повторное добавление обычно не создаёт дубликат.</p><hr><h2 id="активные-и-неактивные-правила" tabindex="-1">Активные и неактивные правила <a class="header-anchor" href="#активные-и-неактивные-правила" aria-label="Permalink to &quot;Активные и неактивные правила&quot;">​</a></h2><p>Список правил делится на два состояния.</p><ul><li><strong>Активные</strong> (<strong>Blocked</strong>) — правило применяется, и совпавшие компоненты скрываются из дерева.</li><li><strong>Неактивные</strong> (<strong>Off</strong>) — запись сохраняется, но временно не участвует в фильтрации.</li></ul><p>Переключение состояния позволяет быстро отключать и повторно включать правило без повторного ввода имени.</p><p>Удаление строки полностью убирает правило из списка.</p><p>Если активных правил нет, фильтрация по чёрному списку фактически не применяется.</p><hr><h2 id="как-сопоставляется-имя" tabindex="-1">Как сопоставляется имя <a class="header-anchor" href="#как-сопоставляется-имя" aria-label="Permalink to &quot;Как сопоставляется имя&quot;">​</a></h2><p>Сравнение выполняется по <strong>имени компонента</strong>, которое отображается в инспекторе.</p><ul><li>Если правило <strong>не содержит</strong> символов <strong><code>*</code></strong> или <strong><code>%</code></strong>, используется <strong>точное совпадение</strong> без учёта регистра.</li><li>Символы <strong><code>*</code></strong> и <strong><code>%</code></strong> работают как шаблон подстановки произвольного фрагмента имени.</li></ul><p>Например:</p><ul><li><code>MyButton</code> — скрывает только компонент с точным именем <strong>MyButton</strong>;</li><li><code>Base*</code> — скрывает все компоненты, имя которых начинается с <strong>Base</strong>;</li><li><code>*Modal*</code> — скрывает все имена, содержащие <strong>Modal</strong>.</li></ul><p>Для безымянных компонентов может использоваться внутреннее обозначение вроде <strong>Anonymous</strong>, если оно присутствует в дереве.</p><hr><h2 id="исключения-и-пересечения" tabindex="-1">Исключения и пересечения <a class="header-anchor" href="#исключения-и-пересечения" aria-label="Permalink to &quot;Исключения и пересечения&quot;">​</a></h2><p>Если компонент подходит сразу под несколько правил, учитывается текущее состояние каждого правила.</p><p>Неактивная запись сама по себе не действует как исключение, а просто временно исключается из фильтрации.</p><p>Если используется широкая маска, удобнее временно отключить её и проверить результат, чем создавать несколько похожих правил.</p><hr><h2 id="когда-применяется" tabindex="-1">Когда применяется <a class="header-anchor" href="#когда-применяется" aria-label="Permalink to &quot;Когда применяется&quot;">​</a></h2><p>Актуальный список правил используется при каждом обновлении дерева:</p><ul><li>при ручном <strong>Refresh</strong>;</li><li>при автоматическом обновлении списка;</li><li>при повторном открытии вкладки.</li></ul><p>После изменения правил в <strong>Options</strong> дерево обычно обновляется, чтобы таблица сразу отразила новый набор компонентов.</p><p>Пока правило активно, скрытые компоненты недоступны для выбора в таблице и карточке.</p><hr><h2 id="практические-советы" tabindex="-1">Практические советы <a class="header-anchor" href="#практические-советы" aria-label="Permalink to &quot;Практические советы&quot;">​</a></h2><ul><li>Начинать удобнее с <strong>точного имени</strong> через контекстное меню строки.</li><li><strong>Широкие маски</strong> подходят для повторяющихся служебных компонентов, но требуют аккуратности.</li><li>Чёрный список влияет только на <strong>отображение в инспекторе</strong> и не изменяет работу Vue-приложения.</li></ul><hr><h2 id="см-также" tabindex="-1">См. также <a class="header-anchor" href="#см-также" aria-label="Permalink to &quot;См. также&quot;">​</a></h2><ul><li><a href="/qa-tools/docs/ru/props/general.html">Основные возможности Props</a></li><li><a href="/qa-tools/docs/ru/props/inspect.html">Инспектор (выбор на странице)</a></li><li><a href="/qa-tools/docs/ru/options/customize.html">Персонализация / настройки</a></li></ul>',40)])])}const u=r(n,[["render",l]]);export{c as __pageData,u as default};
